function BasicLoadingButtonGroupDemo() {
  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

  return (
    <LoadingButtonGroup
      variant="contained"
      loadingSize="1rem"
      buttons={[
        {
          text: '同步操作',
          async: false,
          onClick: () => {
            // do something sync
          },
        },
        {
          text: '异步提交',
          async: true,
          onClick: async () => {
            await sleep(1200);
          },
        },
      ]}
    />
  );
}

function CustomLoadingStyleDemo() {
  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

  return (
    <LoadingButton
      variant="contained"
      loadingColor="#602DED"
      loadingSize="1.125rem"
      sx={{ backgroundColor: '#EFEDF5', color: '#1A1E22' }}
      onClick={async () => {
        await sleep(1200);
      }}
    >
      保存
    </LoadingButton>
  );
}
